import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"What is CZero","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/what-is-czero.md","filePath":"en/guide/what-is-czero.md","lastUpdated":1783349713000}'),o={name:"en/guide/what-is-czero.md"};function r(i,e,l,d,c,p){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="what-is-czero" tabindex="-1">What is CZero <a class="header-anchor" href="#what-is-czero" aria-label="Permalink to &quot;What is CZero&quot;">​</a></h1><p>CZero is an Android root module that cleans the cache of frequently used apps, and adds background suppression, empty-folder cleanup, and F2FS garbage collection.</p><p>The module has no resident service — a lightweight C++ daemon schedules every task according to <code>config.json</code>, and configuration changes take effect immediately. Day-to-day operation goes through the native companion app <strong>CZeroX</strong>.</p><h2 id="the-problem-it-solves" tabindex="-1">The problem it solves <a class="header-anchor" href="#the-problem-it-solves" aria-label="Permalink to &quot;The problem it solves&quot;">​</a></h2><p>Over time, app caches and lingering background processes eat up storage and memory, and the device gradually slows down with less free space. CZero handles cleaning and suppression automatically in the background on a schedule, keeping the device clean and responsive without manual effort.</p><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design principles&quot;">​</a></h2><ul><li><strong>No resident service</strong> — no Java process stays running; all scheduling is handled by a tiny C++ daemon built on <code>timerfd</code> + <code>epoll</code>, at near-zero cost.</li><li><strong>Single source of truth</strong> — all behavior lives in one <code>config.json</code>, read directly by the daemon and every cleaner, with no intermediate derived files.</li><li><strong>Instant effect</strong> — the daemon watches <code>config.json</code> for changes and hot-reloads; a broken config keeps the last-good job set and never interrupts service.</li><li><strong>Native frontend</strong> — day-to-day operation goes through the native CZeroX app, no WebUI.</li></ul><h2 id="three-layer-architecture" tabindex="-1">Three-layer architecture <a class="header-anchor" href="#three-layer-architecture" aria-label="Permalink to &quot;Three-layer architecture&quot;">​</a></h2><p>CZero is made of three cooperating layers:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Component</th><th>Role</th></tr></thead><tbody><tr><td>Install</td><td><code>customize.sh</code></td><td>Volume-key language selection, config-inheritance prompts</td></tr><tr><td>Boot</td><td><code>service.sh</code> → <code>service</code> (C++)</td><td>Marks the module active, prepares the stats file, fixes permissions, starts the daemon</td></tr><tr><td>Runtime</td><td><code>cron/timer_daemon</code> (C++)</td><td>Parses <code>config.json</code>, schedules and spawns all cleaning jobs, hot-reloads on change</td></tr></tbody></table><h2 id="runtime-files" tabindex="-1">Runtime files <a class="header-anchor" href="#runtime-files" aria-label="Permalink to &quot;Runtime files&quot;">​</a></h2><p>All runtime files live under <code>/data/adb/modules/CZero/</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config.json            # single source of truth (read directly by daemon + cleaners)</span></span>
<span class="line"><span>basis/basis.prop       # cleaning statistics</span></span>
<span class="line"><span>cron/state             # last-run timestamps for jobs with a period &gt;= 1 day</span></span>
<span class="line"><span>list/Tencent/…         # detection &amp; cleaning scripts for frequently used apps</span></span>
<span class="line"><span>list/suppress/…        # background suppressor</span></span>
<span class="line"><span>list/GCclean/…         # F2FS GC script</span></span>
<span class="line"><span>list/Emptyfolder/…     # empty-folder sweeper</span></span>
<span class="line"><span>log/&lt;YYYY-MM-DD&gt;.log   # single shared daily log (only today&#39;s kept)</span></span></code></pre></div><p>The recycle bin produced by cleaning lives outside the module directory, on internal storage at <code>/storage/emulated/0/Recycle/</code>, where cleaned files are kept recoverable for 7 days. See <a href="/en/guide/features#recycle-bin-restore">Features · Recycle bin &amp; restore</a>.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>Android 9+ (API 28), <code>arm64-v8a</code></li><li>Root via Magisk, KernelSU, or APatch</li><li>F2FS <code>/data</code> partition (only for the GC feature; everything else works regardless)</li></ul><p>Ready? Head to <a href="/en/guide/getting-started">Install &amp; Setup</a>.</p>`,17)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
